problem 3 can be solved using dp,
let dp[i][j]=no of arrays possible arraays of length 'i' having the ith element as 'j'
then,
dp[i][j]=dp[i-1][j-1]+dp[i-1][j-2]+...+dp[i-1][0]

```
#include<bits/stdc++.h>
using namespace std;
#define int long long

const int mx=1e4+10;

signed main()
{
    int n;
    cin>>n;
    vector <int> a(n+1),b(n+1);
    for(int i=1;i<=n;i++)cin>>a[i];
    for(int i=1;i<=n;i++)
    {
        cin>>b[i];
        if(a[i]>b[i])swap(a[i],b[i]);
    }

    int dp[n+1][mx]={};
    dp[0][0]=1;
    for(int i=1;i<=n;i++)
    {
        int pre=0;
        for(int j=0;j<=a[i]-1;j++)pre+=dp[i-1][j];

        for(int j=a[i];j<=b[i];j++)
        {
            dp[i][j]=pre;
            pre+=dp[i-1][j];
        }
    }

    int ans=0;
    for(int j=a[n];j<=b[n];j++)ans+=dp[n][j];
    cout<<ans;
    return 0;
}
