solution to [#2](https://leetcode.com/problems/add-two-numbers) 

// "static void main" must be defined in a public class.
public class Main {
    public static void main(String[] args) {
        System.out.println("Hello World!");
        System.out.println(count ( new int[]{6,2,4,4} , new int[]{1,5,1,6}));
    }

    public static int count(int[] a , int[] b){
        int[] res = new int[10002];
        Arrays.fill(res , 1);

        for(int i = a.length -1 ; i >= 0 ; i--){
            int[] tmp = new int[10002];
            int min = Math.min(a[i] , b[i]);
            int max = Math.max(a[i] , b[i]);


            for(int j = max ; j >= min ; j--){
                tmp[j] = tmp[j+1] + res[j+1];
            }
            //System.out.println(Arrays.toString(tmp));
            res = tmp;
        }

           int min = Math.min(a[0] , b[0]);
        int max = Math.max(a[0] , b[0]);
        int total = 0;

        for(int i = min ; i <= max ; i++ ) total += res[i];

        return total;

    }
}
